// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if(g_form.getValue('u_ou_parent') + '' != ''){

		if (isLoading || newValue === '') {
			return;
		}

		var currentSysId = g_form.getUniqueValue();
		var isNewRecord = g_form.isNewRecord();

		var status = g_form.getValue('u_status');

		// 2.8 | 2022-04-18 | mmcc | STRY0119470  - All Tasker users (even GHA and TAA) access to use organization requests (button currently hidden from GHA and TAA
		if (status == "In progress" && isNewRecord == false) {
			g_form.setMandatory("u_response_comments", true);
		}

		if (status == "Completed"){
			g_form.setReadOnly("u_request_comments", true);
			g_form.setReadOnly("u_response_comments", true);
		}
	}

	// it changed, checking against old value would compare only to the original value which will be blank when the user can change this
	if(newValue != ''){
		// get the old value default setting
		var oldValueDefaultComment = '';
		var currentComments = g_form.getValue('u_request_comments');
		// DFCT0010475 - opened and closed in 2.7
		if(g_form.getValue('u_ou_parent') + '' != '' &&
			currentComments != '' &&
			currentComments != getMessage('Tasker - OU Request - Member Add - Comment') && 
			currentComments != getMessage('Tasker - OU Request - Member Remove - Comment') &&
			currentComments != getMessage('Tasker - OU Request - Member Update - Comment') &&
			currentComments != getMessage('Tasker - OU Request - Sub OU Add - Comment') &&
			currentComments != getMessage('Tasker - OU Request - Sub OU Remove - Comment') &&
			currentComments != getMessage('Tasker - OU Request - OU Update - Comment') &&
			currentComments != getMessage('Tasker - OU Request - OU Remove - Comment')){

			var confirmChangeMsg = getMessage('Tasker - Confirm Change of OU Request Type');
			if(typeof spModal != 'undefined'){
				spModal.confirm(confirmChangeMsg).then(function(confirmed) {
					if(confirmed){
						changeComment(newValue);	
					} else {
						return false;
					}
				});
			} else if (typeof spModal == 'undefined' && g_form.modified) {
				// start as true, if no changes it will return true, if changes confirmation will have to set back to true
				if(confirm(confirmChangeMsg)){
					changeComment(newValue);
				} else{
					return false;
				}
			}			
		} else {
			changeComment(newValue);
		}
	}

	function changeComment(newValue){
		// if confirmed throw away, continue and reset the comments
		switch (newValue){
			case 'member_add':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - Member Add - Comment'));
				break;
			case 'member_remove':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - Member Remove - Comment'));
				break;
			case 'member_update':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - Member Update - Comment'));
				break;				
			case 'sub_ou_add':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - Sub OU Add - Comment'));
				break;
			case 'sub_ou_remove':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - Sub OU Remove - Comment'));
				break;				
			case 'ou_update':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - OU Update - Comment'));
				break;
			case 'ou_remove':
				g_form.setValue('u_request_comments', getMessage('Tasker - OU Request - OU Remove - Comment'));
				break;
		}			
	}	
}
